#include <bits/stdc++.h>
using namespace std;
int n,k,a[7];
long long dfs(int leave,int x){
    if(x==k)return 1;
    long long sum=0;
    for(int i=a[x-1];i*(k-x+1)<=leave;i++){
        a[x]=i;
        sum+=dfs(leave-i,x+1);
    }
    return sum;
}
int main(){
    a[0]=1;
    cin>>n>>k;
    cout<<dfs(n,1);
    return 0;
}
